.darma-loader-uiverse-hourglass-sand__hourglassBackground {
  position: relative;
  background-color: var(--loader-bg, #473c3c);
  height: 130px;
  width: 130px;
  border-radius: 50%;
  margin: 30px auto;
}
.darma-loader-uiverse-hourglass-sand__hourglassContainer {
  position: absolute;
  top: 30px;
  left: 40px;
  width: 50px;
  height: 70px;
  animation: darma-loader-uiverse-hourglass-sand-hourglassRotate 2s ease-in 0s infinite;
  transform-style: preserve-3d;
  perspective: 1000px;
}
.darma-loader-uiverse-hourglass-sand__hourglassContainer div, .darma-loader-uiverse-hourglass-sand__hourglassContainer div:before, .darma-loader-uiverse-hourglass-sand__hourglassContainer div:after { transform-style: preserve-3d; }
@keyframes darma-loader-uiverse-hourglass-sand-hourglassRotate { 0% { transform: rotateX(0deg); } 50%, 100% { transform: rotateX(180deg); } }
.darma-loader-uiverse-hourglass-sand__hourglassCapTop { top: 0; }
.darma-loader-uiverse-hourglass-sand__hourglassCapTop:before { top: -25px; }
.darma-loader-uiverse-hourglass-sand__hourglassCapTop:after { top: -20px; }
.darma-loader-uiverse-hourglass-sand__hourglassCapBottom { bottom: 0; }
.darma-loader-uiverse-hourglass-sand__hourglassCapBottom:before { bottom: -25px; }
.darma-loader-uiverse-hourglass-sand__hourglassCapBottom:after { bottom: -20px; }
.darma-loader-uiverse-hourglass-sand__hourglassGlassTop {
  transform: rotateX(90deg);
  position: absolute;
  top: -16px;
  left: 3px;
  border-radius: 50%;
  width: 44px;
  height: 44px;
  background-color: var(--loader-secondary-color, #999999);
}
.darma-loader-uiverse-hourglass-sand__hourglassGlass {
  perspective: 100px;
  position: absolute;
  top: 32px;
  left: 20px;
  width: 10px;
  height: 6px;
  background-color: var(--loader-secondary-color, #999999);
  opacity: 0.5;
}
.darma-loader-uiverse-hourglass-sand__hourglassGlass:before, .darma-loader-uiverse-hourglass-sand__hourglassGlass:after {
  content: '';
  display: block;
  position: absolute;
  background-color: var(--loader-secondary-color, #999999);
  left: -17px;
  width: 44px;
  height: 28px;
}
.darma-loader-uiverse-hourglass-sand__hourglassGlass:before { top: -27px; border-radius: 0 0 25px 25px; }
.darma-loader-uiverse-hourglass-sand__hourglassGlass:after { bottom: -27px; border-radius: 25px 25px 0 0; }
.darma-loader-uiverse-hourglass-sand__hourglassCurves:before, .darma-loader-uiverse-hourglass-sand__hourglassCurves:after {
  content: '';
  display: block;
  position: absolute;
  top: 32px;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background-color: #333;
  animation: darma-loader-uiverse-hourglass-sand-hideCurves 2s ease-in 0s infinite;
}
.darma-loader-uiverse-hourglass-sand__hourglassCurves:before { left: 15px; }
.darma-loader-uiverse-hourglass-sand__hourglassCurves:after { left: 29px; }
@keyframes darma-loader-uiverse-hourglass-sand-hideCurves { 0%, 40%, 100% { opacity: 1; } 25%, 30% { opacity: 0; } }
.darma-loader-uiverse-hourglass-sand__hourglassSandStream:before {
  content: '';
  display: block;
  position: absolute;
  left: 24px;
  width: 3px;
  background-color: var(--loader-color, #ffffff);
  animation: darma-loader-uiverse-hourglass-sand-sandStream1 2s ease-in 0s infinite;
}
.darma-loader-uiverse-hourglass-sand__hourglassSandStream:after {
  content: '';
  display: block;
  position: absolute;
  top: 36px;
  left: 19px;
  border-left: 6px solid transparent;
  border-right: 6px solid transparent;
  border-bottom: 6px solid var(--loader-color, #ffffff);
  animation: darma-loader-uiverse-hourglass-sand-sandStream2 2s ease-in 0s infinite;
}
@keyframes darma-loader-uiverse-hourglass-sand-sandStream1 { 0% { height: 0; top: 35px; } 50% { height: 0; top: 45px; } 60%, 85% { height: 35px; top: 8px; } 100% { height: 0; top: 8px; } }
@keyframes darma-loader-uiverse-hourglass-sand-sandStream2 { 0%, 50%, 91%, 100% { opacity: 0; } 51%, 90% { opacity: 1; } }
.darma-loader-uiverse-hourglass-sand__hourglassSand:before, .darma-loader-uiverse-hourglass-sand__hourglassSand:after {
  content: '';
  display: block;
  position: absolute;
  left: 6px;
  background-color: var(--loader-color, #ffffff);
  perspective: 500px;
}
.darma-loader-uiverse-hourglass-sand__hourglassSand:before { top: 8px; width: 39px; border-radius: 3px 3px 30px 30px; animation: darma-loader-uiverse-hourglass-sand-sandFillup 2s ease-in 0s infinite; }
.darma-loader-uiverse-hourglass-sand__hourglassSand:after { border-radius: 30px 30px 3px 3px; animation: darma-loader-uiverse-hourglass-sand-sandDeplete 2s ease-in 0s infinite; }
@keyframes darma-loader-uiverse-hourglass-sand-sandFillup { 0% { opacity: 0; height: 0; } 60% { opacity: 1; height: 0; } 100% { opacity: 1; height: 17px; } }
@keyframes darma-loader-uiverse-hourglass-sand-sandDeplete {
  0% { opacity: 0; top: 45px; height: 17px; width: 38px; left: 6px; }
  1%, 24% { opacity: 1; top: 45px; height: 17px; width: 38px; left: 6px; }
  25%, 50% { opacity: 1; top: 41px; height: 17px; width: 38px; left: 6px; }
  90% { opacity: 1; top: 41px; height: 0; width: 10px; left: 20px; }
}

